```hcl
# Terraform：最小 EBS 快照生命周期策略
resource "aws_dlm_lifecycle_policy" "<example_resource_name>" {
  description        = "<description>"
  execution_role_arn = "<example_resource_arn>"
  state              = "ENABLED" # 关键：启用策略以便检查可以计数

  policy_details {
    policy_type    = "EBS_SNAPSHOT_MANAGEMENT" # 关键：创建 EBS 快照生命周期策略
    resource_types = ["VOLUME"]
    target_tags = {
      "<tag_key>" = "<tag_value>" # 关键：通过标签选择目标卷
    }
    schedule {
      create_rule {
        interval      = 24
        interval_unit = "HOURS"
      }
      retain_rule {
        count = 1
      }
    }
  }
}
```
